arguments.file_text:
@page "/catalog"
@rendermode InteractiveServer
@using sv_c6bb25dd82e14d2fa0f15764d19fd691.Components.Catalog
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="catalog-layout">
    <aside class="catalog-sidebar-col">
        <CatalogSidebar Categories="_categories"
                        OnFilterApplied="HandleFilterApplied" />
    </aside>
    <main class="catalog-main-col">
        <CatalogToolbar SortBy="@_sortBy"
                        TotalCount="_totalCount"
                        Page="_currentPage"
                        PageSize="PageSize"
                        OnSortChanged="HandleSortChanged" />

        <ProductGrid Products="_products"
                     Loading="_loading"
                     ErrorMessage="@_errorMessage"
                     OnProductSelected="OnProductSelected"
                     OnAddToCart="OnAddToCart" />

        <CatalogPagination CurrentPage="_currentPage"
                           TotalPages="_totalPages"
                           OnPageChanged="HandlePageChanged" />
    </main>
</div>

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await SearchAsync();
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            // Categories failing shouldn't block the page;
            // the sidebar will show "Loading…" until they arrive.
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _errorMessage = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products. {ex.Message}";
            _products = [];
            _totalCount = 0;
            _totalPages = 0;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar-col {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main-col {
    flex: 1;
    min-width: 0;
}

@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar-col {
        flex: none;
        max-width: 100%;
    }
}

